mapper.insert:
	INSERT INTO TBSRSYSBS (
		 SYS_CD		
		,SYS_NM		
		,SYS_CD_DESC		
		,CRG_MAN_NM		
	) VALUES (
		 #{sysCd, jdbcType = VARCHAR}
 		,#{sysNm, jdbcType = VARCHAR}
 		,#{sysCdDesc, jdbcType = VARCHAR}
 		,#{crgManNm, jdbcType = VARCHAR}
  	)

mapper.update:
	UPDATE TBSRSYSBS 
	SET
 		SYS_NM = #{sysNm, jdbcType = VARCHAR}		
  		,SYS_CD_DESC = #{sysCdDesc, jdbcType = VARCHAR}		
  		,CRG_MAN_NM = #{crgManNm, jdbcType = VARCHAR}
  		,NONCORE_YN = #{noncoreYn, jdbcType = VARCHAR}		
   	WHERE SYS_CD = #{sysCd, jdbcType = VARCHAR}

	UPDATE TB_EAI_CD_DMN_CD_VAL_I 
	SET
		EAI_IF_DATA_APLY_TMSTMP = #{ifDataAplyTmstmp, jdbcType = VARCHAR}
